import jwt from "jsonwebtoken";
import { prisma } from "../config/db.js";
import { Request, Response, NextFunction, response } from "express";

export const authMiddleware = async (
  req: Request,
  res: Response,
  next: NextFunction,
) => {
  let token;

  if (
    req.headers.authorization &&
    req.headers.authorization.startsWith("Bearer")
  ) {
    token = req.headers.authorization.split(" ")[1];
  } else if (req.cookies?.jwt) {
    token = req.cookies.jwt;
  }

  if (!token) {
    return res.status(401).json({ error: "Not authorized, no token provided" });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET as string) as {
      id: string;
    };

    const user = await prisma.user.findUnique({
      where: { id: decoded.id },
      select: {
        id: true,
        firstName: true,
        lastName: true,
        email: true,
        role: true,
        cards: true,
        discount: true,
        phone: true,
        address: true,
        city: true,
        country: true,
        zipCode: true,
        companyName: true,
        companyAddress: true,
        companyCity: true,
        companyDIC: true,
        companyICO: true,
        companyZipCode: true,
      },
    });

    if (!user) {
      return res.status(401).json({ error: "User no longer exists" });
    }
    req.user = user;
    next();
  } catch (error) {
    return res.status(401).json({ error: "Not authorized, token failed" });
  }
};
export const softAuth = async (
  req: Request,
  res: Response,
  next: NextFunction,
) => {
  let token =
    req.cookies?.jwt ||
    (req.headers.authorization?.startsWith("Bearer") &&
      req.headers.authorization.split(" ")[1]);

  if (!token) {
    req.user = null;
    return next();
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET as string) as {
      id: string;
    };
    const user = await prisma.user.findUnique({
      where: { id: decoded.id },
      select: {
        firstName: true,
        lastName: true,
        email: true,
        role: true,
        cards: true,
        discount: true,
        phone: true,
        address: true,
        city: true,
        country: true,
        zipCode: true,
        companyName: true,
        companyAddress: true,
        companyCity: true,
        companyDIC: true,
        companyICO: true,
        companyZipCode: true,
      },
    });
    req.user = user || null;
  } catch (error) {
    req.user = null;
  }
  next();
};
